SELECT worm_id, worm_name
FROM worms
WHERE age > 5;

SELECT worm_name
FROM worms
WHERE worm_id = 0;

SELECT frame_rate
FROM frames
WHERE frame_id = 0;

SELECT AVG(x_position) AS avg_x_position
FROM worm_positions
WHERE worm_id = 0;

SELECT AVG(x_velocity) AS avg_x_velocity, AVG(y_velocity) AS avg_y_velocity
FROM velocities
WHERE worm_id = 0 AND frame_id = 0;
